#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,id;
    bool operator<(const node&b)const
    {
        if(x-id==b.x-b.id)
        {
            return id<b.id;
        }
        return (x-id)>(b.x-b.id);
    }
}a[100010];
int n;
int s[1000010];
int lowbit(int x)
{
    return x&-x;
}
void update(int x,int v)
{
    for(int i=x;i<=1000000;i+=lowbit(i))
    {
        s[i]=max(s[i],v);
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans=max(ans,s[i]);
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i].x);
        a[i].id=i;
    }
    sort(a+1,a+1+n);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(a[i].x>a[i].id)
        {
            continue;
        }
        int f=query(a[i].x-1)+1;
        update(a[i].x,f);
        ans=max(ans,f);
    }
    printf("%d",ans);
    return 0;
}
